import{_ as e,o as l,c as a,ae as o}from"./chunks/framework.BEtfQoF7.js";const m=JSON.parse('{"title":"컨텍스트 윈도우 탐색","description":"Claude Code의 컨텍스트 윈도우가 세션 중에 어떻게 채워지는지에 대한 인터랙티브 시뮬레이션. 자동으로 로드되는 항목, 각 파일 읽기 비용, Rules와 Hooks가 실행되는 시점을 확인할 수 있습니다.","frontmatter":{"title":"컨텍스트 윈도우 탐색","description":"Claude Code의 컨텍스트 윈도우가 세션 중에 어떻게 채워지는지에 대한 인터랙티브 시뮬레이션. 자동으로 로드되는 항목, 각 파일 읽기 비용, Rules와 Hooks가 실행되는 시점을 확인할 수 있습니다."},"headers":[],"relativePath":"context-window.md","filePath":"context-window.md","lastUpdated":1776205703000}'),d={name:"context-window.md"};function s(c,t,r,i,n,h){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="컨텍스트-윈도우-탐색" tabindex="-1">컨텍스트 윈도우 탐색 <a class="header-anchor" href="#컨텍스트-윈도우-탐색" aria-label="Permalink to &quot;컨텍스트 윈도우 탐색&quot;">​</a></h1><p>Claude Code의 컨텍스트 윈도우는 세션에서 Claude가 알고 있는 모든 것을 담고 있습니다: 여러분의 지시사항, 읽은 파일, Claude 자신의 응답, 그리고 터미널에 표시되지 않는 콘텐츠가 포함됩니다. 아래의 타임라인은 무엇이 언제 로드되는지를 보여줍니다. 동일한 내용을 목록으로 보려면 <a href="#타임라인이-보여주는-것">아래의 상세 설명</a>을 참조하세요.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>이 페이지의 원본에는 컨텍스트 윈도우가 채워지는 과정을 시각화하는 인터랙티브 타임라인이 포함되어 있습니다. 인터랙티브 버전은 <a href="https://docs.anthropic.com/en/docs/claude-code/context-window" target="_blank" rel="noreferrer">원본 영문 문서</a>에서 확인할 수 있습니다.</p></div><h2 id="타임라인이-보여주는-것" tabindex="-1">타임라인이 보여주는 것 <a class="header-anchor" href="#타임라인이-보여주는-것" aria-label="Permalink to &quot;타임라인이 보여주는 것&quot;">​</a></h2><p>이 세션은 대표적인 토큰 수와 함께 현실적인 흐름을 보여줍니다:</p><ul><li><strong>아무것도 입력하기 전</strong>: CLAUDE.md, 자동 메모리, MCP 도구 이름, Skills 설명이 모두 컨텍스트에 로드됩니다. 여러분의 설정에 따라 <a href="/claude-code-docs-ko/output-styles.html">출력 스타일</a>이나 <a href="/claude-code-docs-ko/cli-reference.html"><code>--append-system-prompt</code></a>의 텍스트 등이 추가로 로드될 수 있으며, 이들은 같은 방식으로 시스템 프롬프트에 포함됩니다.</li><li><strong>Claude가 작업하는 동안</strong>: 파일을 읽을 때마다 컨텍스트에 추가되고, <a href="/claude-code-docs-ko/memory.html#path-specific-rules">경로 기반 Rules</a>는 매칭되는 파일과 함께 자동으로 로드되며, <a href="/claude-code-docs-ko/hooks-guide.html">PostToolUse Hook</a>이 각 편집 후에 실행됩니다.</li><li><strong>후속 프롬프트</strong>: <a href="/claude-code-docs-ko/sub-agents.html">서브에이전트</a>가 자체 별도 컨텍스트 윈도우에서 조사를 처리하므로, 대용량 파일 읽기가 여러분의 컨텍스트에 포함되지 않습니다. 요약과 작은 메타데이터 트레일러만 돌아옵니다.</li><li><strong>마지막에</strong>: <code>/compact</code>이 대화를 구조화된 요약으로 대체합니다. 대부분의 시작 콘텐츠는 자동으로 다시 로드됩니다. 각 메커니즘에 어떤 일이 일어나는지는 아래 표를 참조하세요.</li></ul><h2 id="압축-compaction-후-유지되는-것" tabindex="-1">압축(Compaction) 후 유지되는 것 <a class="header-anchor" href="#압축-compaction-후-유지되는-것" aria-label="Permalink to &quot;압축(Compaction) 후 유지되는 것&quot;">​</a></h2><p>긴 세션이 압축되면, Claude Code는 대화 기록을 요약하여 컨텍스트 윈도우에 맞춥니다. 여러분의 지시사항이 어떻게 되는지는 로드 방식에 따라 달라집니다:</p><table tabindex="0"><thead><tr><th style="text-align:left;">메커니즘</th><th style="text-align:left;">압축 후</th></tr></thead><tbody><tr><td style="text-align:left;">시스템 프롬프트와 출력 스타일</td><td style="text-align:left;">변경 없음; 메시지 기록의 일부가 아님</td></tr><tr><td style="text-align:left;">프로젝트 루트 CLAUDE.md와 범위 없는 Rules</td><td style="text-align:left;">디스크에서 재주입</td></tr><tr><td style="text-align:left;">자동 메모리</td><td style="text-align:left;">디스크에서 재주입</td></tr><tr><td style="text-align:left;"><code>paths:</code> 프론트매터가 있는 Rules</td><td style="text-align:left;">매칭되는 파일이 다시 읽힐 때까지 손실</td></tr><tr><td style="text-align:left;">하위 디렉토리의 중첩 CLAUDE.md</td><td style="text-align:left;">해당 하위 디렉토리의 파일이 다시 읽힐 때까지 손실</td></tr><tr><td style="text-align:left;">호출된 Skill 본문</td><td style="text-align:left;">재주입되며, Skill당 5,000 토큰, 총 25,000 토큰으로 제한; 가장 오래된 것부터 제거</td></tr><tr><td style="text-align:left;">Hooks</td><td style="text-align:left;">해당 없음; Hooks는 컨텍스트가 아닌 코드로 실행됨</td></tr></tbody></table><p>경로 기반 Rules와 중첩 CLAUDE.md 파일은 트리거 파일이 읽힐 때 메시지 기록에 로드되므로, 압축 시 다른 모든 것과 함께 요약됩니다. Claude가 매칭되는 파일을 다시 읽으면 다시 로드됩니다. Rule이 압축 후에도 유지되어야 한다면, <code>paths:</code> 프론트매터를 제거하거나 프로젝트 루트 CLAUDE.md로 이동하세요.</p><p>Skill 본문은 압축 후 재주입되지만, 큰 Skill은 Skill당 제한에 맞게 잘리며, 총 예산이 초과되면 가장 오래전에 호출된 Skill부터 제거됩니다. 잘림은 파일의 시작 부분을 유지하므로, 가장 중요한 지시사항을 <code>SKILL.md</code> 상단에 배치하세요.</p><h2 id="자신의-세션-확인하기" tabindex="-1">자신의 세션 확인하기 <a class="header-anchor" href="#자신의-세션-확인하기" aria-label="Permalink to &quot;자신의 세션 확인하기&quot;">​</a></h2><p>시각화에 사용된 수치는 대표적인 값입니다. 실제 컨텍스트 사용량을 확인하려면, <code>/context</code>를 실행하여 카테고리별 실시간 분석과 최적화 제안을 확인하세요. <code>/memory</code>를 실행하면 시작 시 어떤 CLAUDE.md와 자동 메모리 파일이 로드되었는지 확인할 수 있습니다.</p><h2 id="관련-리소스" tabindex="-1">관련 리소스 <a class="header-anchor" href="#관련-리소스" aria-label="Permalink to &quot;관련 리소스&quot;">​</a></h2><p>타임라인에 표시된 기능에 대한 더 자세한 내용은 다음 페이지를 참조하세요:</p><ul><li><a href="/claude-code-docs-ko/features-overview.html">Claude Code 확장하기</a>: CLAUDE.md vs Skills vs Rules vs Hooks vs MCP 사용 시기</li><li><a href="/claude-code-docs-ko/memory.html">지시사항과 메모리 저장하기</a>: CLAUDE.md 계층 구조와 자동 메모리</li><li><a href="/claude-code-docs-ko/sub-agents.html">서브에이전트</a>: 별도의 컨텍스트 윈도우로 조사 위임</li><li><a href="/claude-code-docs-ko/best-practices.html">모범 사례</a>: 주요 제약 조건으로서의 컨텍스트 관리</li><li><a href="/claude-code-docs-ko/costs.html#reduce-token-usage">토큰 사용량 줄이기</a>: 컨텍스트 사용량을 낮게 유지하는 전략</li></ul>',16)])])}const p=e(d,[["render",s]]);export{m as __pageData,p as default};
